    BEGIN{in_block=0}
    {
      line=$0
      # strip block comments — naive
      while (1) {
        s=index(line,"/-")
        e=index(line,"-/")
        if (in_block) {
          if (e>0) { line=substr(line,e+2); in_block=0 } else { line=""; break }
        } else {
          if (s>0) {
            if (e>s) { line=substr(line,1,s-1) substr(line,e+2) }
            else { line=substr(line,1,s-1); in_block=1; break }
          } else break
        }
      }
      # strip line comments
      p=index(line,"--")
      if (p>0) line=substr(line,1,p-1)
      if (match(line,/\<sorry\>/)) print FILENAME":"NR
    }
  ' "$f" 2>/dev/null | wc -l)
  echo "$f: $n"
done

